svg.script:
// Perlin noise implementation
class PerlinNoise {
  constructor(seed = Math.random() * 10000) {
    this.p = [];
    for (let i = 0; i < 256; i++) this.p[i] = i;
    let n = seed;
    for (let i = 255; i > 0; i--) {
      n = (n * 16807) % 2147483647;
      const j = n % (i + 1);
      [this.p[i], this.p[j]] = [this.p[j], this.p[i]];
    }
    this.p = this.p.concat(this.p);
  }

  fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  lerp(a, b, t) { return a + t * (b - a); }
  grad(hash, x) { return (hash & 1) === 0 ? x : -x; }

  noise1D(x) {
    const xi = Math.floor(x) & 255;
    const xf = x - Math.floor(x);
    const u = this.fade(xf);
    return this.lerp(
      this.grad(this.p[xi], xf),
      this.grad(this.p[xi + 1], xf - 1),
      u
    );
  }
}

// Leg configuration - anchored at top (y=32), stretches down
const legs = [
  {
    el: document.getElementById('leg0'),
    noise: new PerlinNoise(1),
    anchorX: -16,  // Fixed x anchor point
    anchorY: 32,   // Fixed y anchor (attached to body)
    baseHeight: 20,
    freqStretch: 1.2,
    freqSkew: 0.8,
    ampStretch: 12,  // How much it can stretch
    ampSkew: 15,     // Skew angle range in degrees
    phase: 0
  },
  {
    el: document.getElementById('leg1'),
    noise: new PerlinNoise(2),
    anchorX: -10,
    anchorY: 32,
    baseHeight: 20,
    freqStretch: 1.0,
    freqSkew: 1.1,
    ampStretch: 10,
    ampSkew: 12,
    phase: 0.8
  },
  {
    el: document.getElementById('leg2'),
    noise: new PerlinNoise(3),
    anchorX: 6,
    anchorY: 32,
    baseHeight: 20,
    freqStretch: 1.1,
    freqSkew: 0.9,
    ampStretch: 10,
    ampSkew: 12,
    phase: 1.6
  },
  {
    el: document.getElementById('leg3'),
    noise: new PerlinNoise(4),
    anchorX: 12,
    anchorY: 32,
    baseHeight: 20,
    freqStretch: 1.3,
    freqSkew: 1.0,
    ampStretch: 12,
    ampSkew: 15,
    phase: 2.4
  }
];

let time = 0;

function animate() {
  time += 0.02;

  legs.forEach(leg => {
    // Perlin noise values
    const noiseStretch = leg.noise.noise1D(time * leg.freqStretch + leg.phase);
    const noiseSkew = leg.noise.noise1D(time * leg.freqSkew + leg.phase + 50);

    // Stretch: base height + noise-driven extension (always positive stretch)
    const stretch = leg.baseHeight + (noiseStretch * 0.5 + 0.5) * leg.ampStretch;

    // Skew angle for sideways reach
    const skewAngle = noiseSkew * leg.ampSkew;

    // Apply height (stretch)
    leg.el.setAttribute('height', stretch);

    // Apply skew transform, anchored at top of leg
    // transform-origin is at the top center of the leg
    const originX = leg.anchorX + 2; // center of 4-wide leg
    const originY = leg.anchorY;

    leg.el.setAttribute('transform',
      `skewX(${skewAngle})`
    );
    leg.el.setAttribute('transform-origin', `${originX}px ${originY}px`);
  });

  requestAnimationFrame(animate);
}

animate();
